def main():
    data_dir = os.path.dirname(os.path.abspath(__file__))
    json_path = os.path.join(data_dir, '..', 'src', 'data', 'exam-questions.json')
    
    with open(json_path, 'r', encoding='utf-8') as f:
        existing = json.load(f)
    
    print(f"现有题目数: {len(existing)}")
    print(f"新增真题数: {len(real_questions)}")
    
    # 去重：按stem去重
    existing_stems = set()
    for q in existing:
        # normalize stem for comparison
        stem = q['stem'].strip().replace('\u2018', "'").replace('\u2019', "'").replace('\u201c', '"').replace('\u201d', '"')
        existing_stems.add(stem[:60])  # first 60 chars for fuzzy matching
    
    new_count = 0
    skip_count = 0
    for q in real_questions:
        stem = q['stem'].strip().replace('\u2018', "'").replace('\u2019', "'").replace('\u201c', '"').replace('\u201d', '"')
        if stem[:60] not in existing_stems:
            existing.append(q)
            existing_stems.add(stem[:60])
            new_count += 1
        else:
            skip_count += 1
    
    print(f"成功新增: {new_count}")
    print(f"重复跳过: {skip_count}")
    print(f"最终总数: {len(existing)}")
    
    # Count by source
    sources = {}
    for q in existing:
        s = q.get('source', 'unknown')
        sources[s] = sources.get(s, 0) + 1
    for k, v in sorted(sources.items(), key=lambda x: -x[1]):
        print(f"  {k}: {v}")
    
    # Filter: only keep 2018+
    before = len(existing)
    existing = [q for q in existing if int(q.get('year', '0')) >= 2018]
    print(f"\n过滤2018年以前后: {len(existing)} (移除了 {before - len(existing)} 题)")
    
    with open(json_path, 'w', encoding='utf-8') as f:
        json.dump(existing, f, ensure_ascii=False, indent=2)
    
    print(f"\n已保存到 {json_path}")
    print(f"最终题目总数: {len(existing)}")

if __name__ == '__main__':
    main()
